noncompliant:
namespace MyLib
{
    public class Foo
    {
        static readonly int x = 1;        // Noncompliant - can be const
        static readonly int y = x + 4;    // Noncompliant - compile-time computable
        static readonly string s = "abc"; // Noncompliant - string literal is const
    }
}

compliant:
namespace MyLib
{
    public class Foo
    {
        const int x = 1;              // Compliant - const
        const int y = x + 4;          // Compliant - const
        const string s = "abc";       // Compliant - const

        static readonly object obj = new object();  // Compliant - not compile-time constant
    }
}
